@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@* In-flow spacer that reserves the fixed bar's footprint so it never overlaps
   the end of the page content. Only meaningful while the nav is Fixed (an inline
   nav already occupies its own space). aria-hidden: purely presentational.
   Height is inline (variant-aware) so it tracks the actual bar; consumers tune it
   via the --lumeo-bottom-nav-height CSS variable rather than overriding the style. *@
@if (Fixed && ReserveSpace)
{
    <div aria-hidden="true" class="lumeo-bottom-nav-spacer" style="@SpacerStyle"></div>
}
<nav class="@CssClass"
     role="navigation"
     aria-label="@EffectiveAriaLabel"
     @attributes="AdditionalAttributes"
     style="padding-bottom: env(safe-area-inset-bottom, 0px);">
    <CascadingValue Value="_context" IsFixed="false">
        <div class="@InnerCssClass">
            @ChildContent
        </div>
    </CascadingValue>
</nav>

@code {
    /// <summary>The <see cref="BottomNavItem"/> (and optionally <see cref="BottomNavFab"/>) elements rendered inside the nav bar.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Accessible label for the nav landmark. Defaults to "Bottom navigation".</summary>
    [Parameter] public string? AriaLabel { get; set; }
    private string EffectiveAriaLabel => AriaLabel ?? L["BottomNav.Label"];

    /// <summary>When true (default), pins to the bottom of the viewport with <c>position: fixed</c>. Set false to render inline.</summary>
    [Parameter] public bool Fixed { get; set; } = true;

    /// <summary>
    /// When <c>true</c> (and <see cref="Fixed"/> is on), also renders an in-flow,
    /// <c>aria-hidden</c> spacer equal to the nav's height plus the bottom safe-area
    /// inset, so the fixed bar never overlaps the end of the page content — no
    /// consumer <c>padding-bottom</c> hack needed. The height is driven by the
    /// <c>--lumeo-bottom-nav-height</c> CSS variable (default <c>3.5rem</c>); override
    /// it if your nav is taller (e.g. the <see cref="BottomNavVariant.Pill"/> variant
    /// or two-line labels). Place <see cref="BottomNav"/> at the end of the scrolling
    /// content so the spacer reserves room there. Default <c>false</c>.
    /// </summary>
    [Parameter] public bool ReserveSpace { get; set; }

    /// <summary>Visual variant. <c>Default</c> is a solid bar with a top border; <c>Pill</c> is a floating centered pill.</summary>
    [Parameter] public BottomNavVariant Variant { get; set; } = BottomNavVariant.Default;

    /// <summary>
    /// When true, each <see cref="BottomNavItem"/> gets smooth background-color
    /// and color transitions, and the small active pill transitions its transform
    /// with a spring easing. Default is <c>false</c>.
    /// </summary>
    [Parameter] public bool AnimatedIndicator { get; set; }

    /// <summary>Additional CSS classes merged onto the root <c>nav</c> element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root <c>nav</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private BottomNavContext? _context;

    protected override void OnParametersSet()
    {
        if (_context is null || _context.AnimatedIndicator != AnimatedIndicator)
        {
            _context = new BottomNavContext(AnimatedIndicator);
        }
    }

    private string CssClass => Cx.Merge(
        Fixed ? "fixed bottom-0 start-0 end-0 z-40" : "w-full",
        Variant == BottomNavVariant.Pill
            ? "px-4 pb-3"
            : "bg-background border-t border-border/40",
        Class);

    // Reserve the full occupied height of the fixed bar: the content height
    // (--lumeo-bottom-nav-height, default 4rem) plus the bottom safe-area inset
    // added exactly ONCE (the nav carries the same inset as interior padding —
    // BottomNav.razor's nav style — so the two never stack). The Pill variant
    // floats with an extra pb-3 (0.75rem) gap below its bar, so reserve that too.
    private string SpacerStyle => Variant == BottomNavVariant.Pill
        ? "height: calc(var(--lumeo-bottom-nav-height, 4rem) + 0.75rem + env(safe-area-inset-bottom, 0px)); flex-shrink: 0;"
        : "height: calc(var(--lumeo-bottom-nav-height, 4rem) + env(safe-area-inset-bottom, 0px)); flex-shrink: 0;";

    private string InnerCssClass => Variant == BottomNavVariant.Pill
        ? "mx-auto flex max-w-md items-center justify-around gap-1 rounded-[calc(var(--radius)*4)] border border-border/40 bg-card/95 shadow-lg backdrop-blur px-2 py-1.5"
        : "flex items-stretch justify-around gap-1 px-2 pt-1.5 pb-1.5";

    public enum BottomNavVariant { Default, Pill }

    public class BottomNavContext
    {
        public BottomNavContext(bool animatedIndicator = false)
        {
            AnimatedIndicator = animatedIndicator;
        }

        /// <summary>True when parent <see cref="BottomNav"/> was configured with <c>AnimatedIndicator="true"</c>.</summary>
        public bool AnimatedIndicator { get; }
    }
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@if (string.IsNullOrEmpty(Href))
{
    <button type="button" class="@CssClass" aria-label="@EffectiveAriaLabel" @onclick="OnClick" @attributes="AdditionalAttributes">
        @ChildContent
    </button>
}
else
{
    <a href="@Href" class="@CssClass" aria-label="@EffectiveAriaLabel" @attributes="AdditionalAttributes">
        @ChildContent
    </a>
}

@code {
    /// <summary>Optional destination URL. When set, renders as an anchor; otherwise a button.</summary>
    [Parameter] public string? Href { get; set; }

    /// <summary>Accessible label. Required because FABs are usually icon-only. Defaults to "Primary action".</summary>
    [Parameter, EditorRequired] public string? AriaLabel { get; set; }
    private string EffectiveAriaLabel => AriaLabel ?? L["BottomNav.PrimaryAction"];

    /// <summary>Invoked when the FAB is activated. Ignored when <see cref="Href"/> is set (the anchor navigates instead).</summary>
    [Parameter] public EventCallback OnClick { get; set; }

    /// <summary>The icon (or other content) rendered inside the floating action button.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Additional CSS classes merged onto the root button/anchor element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root button/anchor element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Raised above the bar so it visually "sits on top" of the nav.
    private string CssClass => Cx.Merge(
        "flex h-12 w-12 -translate-y-3 cursor-pointer items-center justify-center rounded-[calc(var(--radius)*3)] bg-primary text-primary-foreground shadow-lg",
        "transition-transform hover:scale-105 active:scale-95 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ring-offset-2 ring-offset-background",
        Class);
}

@namespace Lumeo
@implements IAsyncDisposable
@inject NavigationManager Nav
@inject Lumeo.Services.IComponentInteropService Interop

@if (string.IsNullOrEmpty(Href))
{
    <button @ref="_el" type="button" class="@CssClass"
            aria-current="@(_active ? "page" : null)"
            aria-label="@Label"
            @onclick="HandleClick"
            @attributes="AdditionalAttributes">
        @RenderBody
    </button>
}
else
{
    <a @ref="_el" href="@Href" class="@CssClass"
       aria-current="@(_active ? "page" : null)"
       aria-label="@Label"
       @attributes="AdditionalAttributes">
        @RenderBody
    </a>
}

@code {
    [CascadingParameter] public BottomNav.BottomNavContext? Context { get; set; }

    /// <summary>Destination URL. When set, item renders as an <c>&lt;a&gt;</c>; otherwise as a <c>&lt;button&gt;</c>.</summary>
    [Parameter] public string? Href { get; set; }

    /// <summary>Text label shown under the icon. Also used as the accessible name.</summary>
    [Parameter] public string? Label { get; set; }

    /// <summary>Icon slot (use <see cref="Lumeo.Icon"/> or <c>&lt;SvgGlyph&gt;</c>). The <c>Content</c> suffix avoids colliding with the <c>&lt;Icon&gt;</c> component.</summary>
    [Parameter] public RenderFragment? IconContent { get; set; }

    /// <summary>Optional badge (count, dot, or any content) shown on the icon. Int, string, or RenderFragment.</summary>
    [Parameter] public RenderFragment? Badge { get; set; }

    /// <summary>
    /// Size class applied to the icon container. Defaults to <c>h-5 w-5</c> to
    /// match the original visual. Override to fit larger content like avatars
    /// (e.g. <c>"h-7 w-7"</c>).
    /// </summary>
    [Parameter] public string IconSize { get; set; } = "h-5 w-5";

    /// <summary>Manual active-state override. When null, active is inferred from the current route matching <see cref="Href"/>.</summary>
    [Parameter] public bool? IsActive { get; set; }

    /// <summary>Click handler — fires for both <c>&lt;a&gt;</c> and <c>&lt;button&gt;</c> renderings (link navigation still proceeds).</summary>
    [Parameter] public EventCallback OnClick { get; set; }

    /// <summary>
    /// Visual feedback when the item is pressed. Default is
    /// <see cref="Button.ButtonPressEffect.None"/>. <c>Scale</c> is recommended
    /// for a tactile feel on mobile.
    /// </summary>
    [Parameter] public Button.ButtonPressEffect PressEffect { get; set; } = Button.ButtonPressEffect.None;

    /// <summary>Additional CSS classes merged onto the root button/anchor element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root button/anchor element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _active;
    private bool _rippleAttached;
    private Microsoft.AspNetCore.Components.ElementReference _el;

    protected override void OnInitialized()
    {
        Nav.LocationChanged += HandleLocationChanged;
        RecomputeActive();
    }

    protected override void OnParametersSet() => RecomputeActive();

    public async ValueTask DisposeAsync()
    {
        Nav.LocationChanged -= HandleLocationChanged;
        if (_rippleAttached)
        {
            _rippleAttached = false;
            try
            {
                await Interop.RippleDetachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    private void HandleLocationChanged(object? sender, Microsoft.AspNetCore.Components.Routing.LocationChangedEventArgs e)
    {
        RecomputeActive();
        StateHasChanged();
    }

    private void RecomputeActive()
    {
        if (IsActive is not null) { _active = IsActive.Value; return; }
        if (string.IsNullOrEmpty(Href)) { _active = false; return; }
        // Compare PATHS only: the query string and fragment never participate in
        // NavLink-style active matching, so a navigation to /orders?status=open
        // or /docs#install must still light up an Href="/orders" item (#243).
        var current = "/" + StripQueryAndFragment(Nav.ToBaseRelativePath(Nav.Uri)).TrimEnd('/');
        // Normalize target so root ("/") stays as "/" — TrimEnd('/') alone would
        // turn it into "" and make every path StartsWith match it. The Href may
        // also carry its own query/fragment; strip those before comparing.
        var hrefPath = StripQueryAndFragment(Href);
        // A fragment-only ("#section") or whitespace ("  ") Href has no route path
        // once the fragment/query is stripped. Treat it as a non-route target so it
        // neither builds a bogus "/  " target nor falsely matches the root "/" (#190).
        if (string.IsNullOrWhiteSpace(hrefPath)) { _active = false; return; }
        var raw = hrefPath.StartsWith('/') ? hrefPath : "/" + hrefPath;
        var target = raw == "/" ? "/" : raw.TrimEnd('/');
        if (target == "/")
        {
            // Root only matches the bare root, never a child route.
            _active = current == "/";
            return;
        }
        _active = string.Equals(current, target, StringComparison.OrdinalIgnoreCase)
                  || current.StartsWith(target + "/", StringComparison.OrdinalIgnoreCase);
    }

    private static readonly char[] QueryFragmentChars = { '?', '#' };

    // Drops everything from the first '?' or '#' onward, whichever comes first.
    private static string StripQueryAndFragment(string path)
    {
        var cut = path.IndexOfAny(QueryFragmentChars);
        return cut >= 0 ? path[..cut] : path;
    }

    private async Task HandleClick()
    {
        if (OnClick.HasDelegate) await OnClick.InvokeAsync();
    }

    private bool IsActiveResolved => _active;

    private bool IsAnimated => Context?.AnimatedIndicator == true;

    private string? PressEffectClass => PressEffect switch
    {
        Button.ButtonPressEffect.Scale => "lumeo-press-scale",
        Button.ButtonPressEffect.Brightness => "lumeo-press-brightness",
        Button.ButtonPressEffect.Ripple => "lumeo-press-ripple",
        _ => null
    };

    private string CssClass => Cx.Merge(
        "group relative flex min-w-0 flex-1 basis-0 flex-col items-center justify-center gap-0.5 rounded-md px-2 py-1.5 text-xs cursor-pointer",
        "transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
        IsActiveResolved ? "text-foreground" : "text-muted-foreground hover:text-foreground",
        Cx.When(IsAnimated, "lumeo-bottom-nav-animated"),
        PressEffectClass,
        Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Reconcile the ripple handler against the CURRENT PressEffect on every
        // render — not just firstRender. An item that switches TO Ripple after the
        // first render must get the handler wired, and one that switches AWAY must
        // have its stale handler torn down (it would otherwise leak / keep firing).
        var wantsRipple = PressEffect == Button.ButtonPressEffect.Ripple;
        if (wantsRipple && !_rippleAttached)
        {
            try
            {
                await Interop.RippleAttachAsync(_el);
                _rippleAttached = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
        else if (!wantsRipple && _rippleAttached)
        {
            _rippleAttached = false;
            try
            {
                await Interop.RippleDetachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    private RenderFragment RenderBody => __builder =>
    {
        <span class="@($"relative flex {IconSize} items-center justify-center")">
            @if (IconContent is not null)
            {
                @IconContent
            }
            @if (Badge is not null)
            {
                <span class="absolute -end-2 -top-1 inline-flex min-w-4 items-center justify-center rounded-[calc(var(--radius)*2)] bg-primary px-1 text-[10px] font-medium text-primary-foreground leading-none h-4">
                    @Badge
                </span>
            }
        </span>
        @if (!string.IsNullOrEmpty(Label))
        {
            <span class="truncate font-medium">@Label</span>
        }
        @if (IsActiveResolved)
        {
            <span aria-hidden="true" class="absolute left-1/2 top-0 h-0.5 w-8 -translate-x-1/2 rounded-[calc(var(--radius)*2)] bg-primary"></span>
        }
    };
}
